mapper.select:
SELECT id, flow_no, merchant_id, flow_type, (CASE flow_type WHEN 1 THEN '收入' WHEN 2 THEN '退款' WHEN 3 THEN '提现' WHEN 4 THEN '服务费扣减' ELSE '未知' END) AS flow_type_text, amount / 100.0 AS amount, before_balance / 100.0 AS before_balance, after_balance / 100.0 AS after_balance, related_no, remark, create_time FROM capital_flow WHERE merchant_id = #{merchantId}
AND flow_type = #{flowType}
ORDER BY create_time DESC
